<template>
	<div class="about">
		<div v-html="articalContent"></div>
		<el-button @click="back" style="width:100px;margin:24px auto">返回</el-button>
	</div>
</template>

<script>
// @ is an alias to /src
// import HelloWorld from '@/components/HelloWorld.vue'
// import api from '../utils/api'
import marked from 'marked'
import { mapState } from 'vuex'
export default {
	name: 'artical',
	data() {
		return {
			articalContent:''
		}
	},
	methods: {
		back() {
			this.$router.push({name: 'home'})
		}
	},
	computed: mapState({
		articalID(){
			return this.$route.query.id
		},
		articalData: state => state.homeArticalData
	}),
	mounted() {
		if (this.articalData.length === 0) {
			return this.$router.push({name: 'home'})
		}
		const findArtical = this.articalData.find(item => item.number === this.articalID)
		this.articalContent = marked(findArtical && findArtical.body || '')
	},
}

</script>
<style>
.about {
	color: #1e1e1e;
}
</style>
